import json
import gzip
import io
from typing import Any, Dict, List

class ParseJSON:
    def __init__(self, json_data: bytes):
        self.json_data = json_data
        self.data = None

    def parse(self):
        self.data = json.JSONDecoder().decode(self.json_data)

def read_gzip_file(filename: str) -> bytes:
    with open(filename, 'rb') as f:
        return f.read()

def parse_json_file(filename: str) -> List[Dict[str, Any]]:
    data = read_gzip_file(filename)
    parse_json = ParseJSON(data)
    parse_json.parse()
    return parse_json.data

if __name__ == '__main__':
    filename = '10GB_of_json_data.json.gz'
    data = parse_json_file(filename)
    print(data)

