#include "driver/gpio.h"

SemaphoreHandle_t mutex;

void get_info(void *pvParameters) 
{
  char buf[100];
  while(1) {
    // Take mutex
    xSemaphoreTake(mutex, portMAX_DELAY);

    // Print system info
    sprintf(buf, "Cores: %d
", esp_cpu_cores_num());
    uart_write_bytes(UART_NUM_1, buf, strlen(buf));
    sprintf(buf, "Clock: %d MHz
", esp_clk_cpu_freq() / 1000000);
    uart_write_bytes(UART_NUM_1, buf, strlen(buf));
    sprintf(buf, "Free heap: %d bytes
", esp_get_free_heap_size());
    uart_write_bytes(UART_NUM_1, buf, strlen(buf));
    sprintf(buf, "Min free heap: %d bytes
", esp_get_minimum_free_heap_size());
    uart_write_bytes(UART_NUM_1, buf, strlen(buf));
    uint32_t id = 0;
    spi_flash_get_chip_size(&id);
    sprintf(buf, "Flash chip size: %d MB
", id / (1024 * 1024));
    uart_write_bytes(UART_NUM_1, buf, strlen(buf));

    // Release mutex
    xSemaphoreGive(mutex);
  }
}

void IRAM_ATTR gpio_isr_handler(void* arg) 
{
  // Take mutex
  xSemaphoreTakeFromISR(mutex, NULL);

  char* cmd = (char*) arg;
  if (strcmp(cmd, "gp") == 0) {
    uart_write_bytes(UART_NUM_1, "ESP32 POST info:
", strlen("ESP32 POST info:
"));
  }

  // Release mutex
  xSemaphoreGiveFromISR(mutex, NULL);
}

void app_main() 
{
  // Create mutex
