void duplicateFaces(manifold::MeshGL& mesh) {
    auto numFaces = mesh.triVerts.size() / 3;
    auto numProp = mesh.numProp;

    auto& triVerts = mesh.triVerts;
    auto& vertProperties = mesh.vertProperties;

    std::vector<float> newVertProperties(numProp * numFaces * 3);
    std::unordered_map<uint32_t, uint32_t> uniqueVertices;

    for(size_t f = 0; f < numFaces; ++f) {
        for(size_t lv = 0; lv < 3; ++lv) {
            size_t v = triVerts[3*f + lv];
            for(size_t i = 0; i < numProp; ++i) {
                newVertProperties[(3*f + lv) * numProp+i] = vertProperties[v * numProp + i];
            }

            // Check if vertex has already been added to uniqueVertices hash map
            if (uniqueVertices.find(v) == uniqueVertices.end()) {
                // If not, add it and assign it a new index
                uniqueVertices[v] = newVertProperties.size() / numProp;
            }

            // Store the corresponding index in the newTriVerts array
            newVertProperties[(3*f + lv) * numProp] = uniqueVertices[v];
        }
    }

