                newMergeTo[3*f + lv] = vNewIndex * 3;
            }

            // Store the new index in the newTriVerts array
            newTriVerts[vNewIndex * 3 + lv] = vNewIndex;
        }
    }

    mesh.triVerts = std::move(newTriVerts);
    mesh.vertProperties = std::move(newVertProperties);
    mesh.mergeFromVert = std::move(newMergeFrom);
    mesh.mergeToVert = std::move(newMergeTo);
}
