    explicit FilteringInsertionIterator(std::vector<int>::iterator begin, std::vector<int>::iterator end, Predicate predicate)
        : it(begin), end(end), predicate(predicate) {}

    void push_back(int value) {
        if (predicate(*it)) {
            *it = value;
            ++it;
        }
    }

    std::vector<int>::iterator begin() const {
        return it;
    }

    std::vector<int>::iterator end() const {
        return end;
    }

private:
    std::vector<int>::iterator it;
    std::vector<int>::iterator end;
    Predicate predicate;
};

int main() {
    std::vector<int> vec = {1, 2, 3, 4, 5, 6, 7, 8, 9};
    Predicate is_even;

    FilteringInsertionIterator it(vec.begin(), vec.end(), is_even);

    it.push_back(10);
    it.push_back(11);

    assert(vec == std::vector<int>{2, 4, 6, 8, 10, 11});

    return 0;
}
```
