```vhdl
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity uart_transmitter is
    port (
        clk                       : in  std_logic;
        rst                       : in  std_logic;
        data_in                   : in  std_logic_vector(7 downto 0); -- 8-bit word
        div_factor                : in  integer range 1 to 256;
        start_transmit            : in  std_logic;
        tx_ready                  : out std_logic
    );
end uart_transmitter;

architecture Behavioral of uart_transmitter is
    signal tx_data                 : std_logic_vector(7 downto 0);
    signal tx_clock                : std_logic;
    signal div_counter             : integer range 0 to div_factor - 1;
    signal transmit_active         : boolean := False;

begin

    -- Process for data transmission
    process (clk, rst)
    variable data_load             : std_logic_vector(7 downto 0);
    variable start_pulse           : std_logic;
    variable data_loaded           : boolean;
    variable div_done              : boolean;
    variable tx_data_loaded        : boolean;

    begin

        -- Reset conditions
        if rst = '1' then
            tx_data                 <= (others => '0');
            div_counter             <= 0;
            transmit_active         <= False;
        elsif rising_edge(clk) then

            -- Load data from input
            if start_transmit = '1' and data_loaded = False then
                data_load             <= data_in;
                data_loaded           <= True;
            end if;

            -- Check if data is loaded
            if data_loaded = True then

                -- Load data to UART register
                if (data_in(7) = '1' and tx_data(7) = '0') or (data_in(7) = '0' and tx_data(7) = '1') then
                    tx_data(7)            <= not data_in(7);
                end if;

                if (data_in(6) = '1' and tx_data(6) = '0') or (data_in(6) = '0' and tx_data(6) = '1') then
                    tx_data(6)            <= not data_in(6);
                end if;

                -- Check if data transmission is complete
                if tx_data = data_load then
                    data_loaded           <= False;
                    div_done              <= True;
                end if;
            end if;

            -- Divide clock and generate transmit clock
            if div_done = True then
                if div_counter = div_factor - 1 then
                    tx_clock              <= '1';
                    div_counter          <= 0;
                    if start_pulse = '1' and transmit_active = False then
                        transmit_active    <= True;
                        tx_ready           <= '1';
                    end if;
                else
                    tx_clock              <= '0';
                    div_counter          <= div_counter + 1;
                end if;
            end if;
        end process;

    -- Outputs
    tx_data_loaded <= (tx_data = data_load);
    start_pulse    <= start_transmit;
    tx_ready       <= not transmit_active;

end Behavioral;
```

