CREATE PROCEDURE GenerateLineItems()
BEGIN
    DECLARE v_contract_id CHAR(36);
    DECLARE v_quantity DECIMAL(10, 2);
    DECLARE v_price DECIMAL(10, 2);
    DECLARE v_currency CHAR(3);
    DECLARE v_pricing_model VARCHAR(36);
    DECLARE v_billing_period_start DATE;
    DECLARE v_billing_period_end DATE;
    DECLARE v_billing_method ENUM('in_advance', 'in_arrears');
    DECLARE v_next_billing_on DATE;

    SET v_contract_id = (SELECT Id FROM Contracts WHERE Status = 'active');
    SET v_quantity = (SELECT Quantity FROM Contracts WHERE Id = v_contract_id);
    SET v_price = (SELECT Price FROM Contracts WHERE Id = v_contract_id);
    SET v_currency = (SELECT Currency FROM Contracts WHERE Id = v_contract_id);
    SET v_pricing_model = (SELECT PricingModel FROM Contracts WHERE Id = v_contract_id);
    SET v_billing_period_start = (SELECT ContractStart FROM Contracts WHERE Id = v_contract_id);
    SET v_billing_period_end = (SELECT ContractEnd FROM Contracts WHERE Id = v_contract_id);
    SET v_billing_method = (SELECT BillingMethod FROM Contracts WHERE Id = v_contract_id);
    SET v_next_billing_on = (SELECT NextBillingOn FROM Contracts WHERE Id = v_contract_id);

    INSERT INTO LineItems (
        ContractId,
        Project,
        Quantity,
        Price,
        Currency,
        PricingModel,
        Item,
        Description,
        TransferredToBilling,
        BillingPeriodStart,
        BillingPeriodEnd,
        CreationDate,
        LastUpdate
    )
    VALUES (
        v_contract_id,
        (SELECT Project FROM Contracts WHERE Id = v_contract_id),
        v_quantity,
        v_price,
        v_currency,
        v_pricing_model,
        (SELECT ArtId FROM Contracts WHERE Id = v_contract_id),
        (SELECT InvoiceText FROM Contracts WHERE Id = v_contract_id),
        (SELECT CreationDate FROM Contracts WHERE Id = v_contract_id),
        v_billing_period_start,
        v_billing_period_end,
        (SELECT LastUpdate FROM Contracts WHERE Id = v_contract_id)
    );

    UPDATE Contracts SET Status = 'invoiced' WHERE Id = v_contract_id;

    IF v_billing_method = 'in_advance' THEN
        SET v_next_billing_on = DATE_ADD(v_next_billing_on, INTERVAL (SELECT BillingPeriod FROM Contracts WHERE Id = v_contract_id) DAY);
    ELSE
        SET v_next_billing_on = DATE_ADD(v_next_billing_on, INTERVAL (SELECT BillingPeriod FROM Contracts WHERE Id = v_contract_id) DAY);
    END IF;

    UPDATE Contracts SET NextBillingOn = v_next_billing_on WHERE Id = v_contract_id;

    SELECT * FROM LineItems WHERE ContractId = v_contract_id;
END;
```
This stored procedure takes no arguments and will generate line items for all active contracts. It will also update the status of the contracts to 'invoiced' and set the next billing date based on the contract's billing method and period. Finally, it will return all line items for the generated contracts.

