Sure! Here's the complete code for the HTML and JavaScript game:

```html
<!DOCTYPE html>
<html>
<head>
    <title>Fish Game</title>
    <style>
        #playArea {
            position: relative;
            width: 500px;
            height: 500px;
            border: 1px solid black;
        }

        .fish {
            position: absolute;
            width: 20px;
            height: 20px;
            border-radius: 50%;
        }

        #yellowFish {
            background-color: yellow;
        }

        .redFish {
            background-color: red;
        }
    </style>
</head>
<body>
    <div id="playArea">
        <div id="yellowFish" class="fish"></div>
    </div>

    <script>
        var playArea = document.getElementById("playArea");
        var yellowFish = document.getElementById("yellowFish");
        var score = 0;
        var speed = 1;

        playArea.addEventListener("mousemove", moveYellowFish);

        function moveYellowFish(event) {
            var x = event.clientX - playArea.offsetLeft;
            var y = event.clientY - playArea.offsetTop;

            yellowFish.style.left = x + "px";
            yellowFish.style.top = y + "px";
        }

        function createRedFish() {
            var redFish = document.createElement("div");
            redFish.className = "fish redFish";
            redFish.style.left = Math.random() * (playArea.offsetWidth - 20) + "px";
            redFish.style.top = Math.random() * (playArea.offsetHeight - 20) + "px";
            playArea.appendChild(redFish);

            moveRedFish(redFish);
        }

        function moveRedFish(redFish) {
            var x = Math.random() * (playArea.offsetWidth - 20);
            var y = Math.random() * (playArea.offsetHeight - 20);

            var dx = x - parseFloat(redFish.style.left);
            var dy = y - parseFloat(redFish.style.top);
            var distance = Math.sqrt(dx * dx + dy * dy);
            var speedX = (dx / distance) * speed;
            var speedY = (dy / distance) * speed;

            var interval = setInterval(function() {
                var currentX = parseFloat(redFish.style.left);
                var currentY = parseFloat(redFish.style.top);

                if (currentX < 0 || currentX > playArea.offsetWidth - 20 || currentY < 0 || currentY > playArea.offsetHeight - 20) {
                    clearInterval(interval);
                    redFish.remove();
                    createRedFish();
                    return;
                }

                redFish.style.left = currentX + speedX + "px";
                redFish.style.top = currentY + speedY + "px";
            }, 20);
        }

        function eatRedFish() {
            score++;
            speed = Math.max(speed, score / 10);

            this.remove();
            createRedFish();
        }

        createRedFish();
        playArea.addEventListener("click", eatRedFish);
    </script>
</body>
</html>
```

This code creates a simple fish game where you play as a yellow fish and try to eat red fish. The yellow fish follows the player's cursor loosely, and red fish are procedurally generated and move randomly in the play area. The score increases as you eat red fish, and the red fish's speed increases as the score goes up.

