public static class DeviceThermalState
{
    public static string GetThermalStateOrBatteryTemp()
    {
#if UNITY_IOS
        switch (Device.thermalState)
        {
            case Device.ThermalState.Critical:
                return "Critical";
            case Device.ThermalState.Fair:
                return "Fair";
            case Device.ThermalState.Nominal:
                return "Nominal";
            case Device.ThermalState.Serious:
                return "Serious";
            case Device.ThermalState.Unknown:
