                return "Unknown";
        }
#elif UNITY_ANDROID
        try
        {
            using (var unityPlayer = new AndroidJavaClass("com.unity3d.player.UnityPlayer"))
            {
                using (var currentActivity = unityPlayer.GetStatic<AndroidJavaObject>("currentActivity"))
                {
                    using (var context = currentActivity.Call<AndroidJavaObject>("getApplicationContext"))
                    {
                        using (var intentFilter = new AndroidJavaObject("android.content.IntentFilter", "android.intent.action.BATTERY_CHANGED"))
                        {
                            using (var batteryIntent = context.Call<AndroidJavaObject>("registerReceiver", null, intentFilter))
                            {
                                int temperature = batteryIntent.Call<int>("getIntExtra", "temperature", -1);
                                float batteryTempCelsius = temperature / 10.0f;
                                return batteryTempCelsius.ToString("F1") + "°C";
                            }
                        }
                    }
                }
            }
        }
        catch (System.Exception e)
        {
            Debug.LogError("Failed to read battery temperature: " + e.Message);
            return "Unavailable";
        }
#else
        return "Unsupported platform";
#endif
    }
}
```

For this code to work, you need to have the appropriate permissions in Android. Make sure you have the `READ_PHONE_STATE` permission in your AndroidManifest.xml file:

```xml
<uses-permission android:name="android.permission.READ_PHONE_STATE" />
```

Keep in mind that the temperature value you get on Android is the battery temperature, not the overall device thermal state. Also, the code for iOS is just a stub that returns the thermal state without any actual temperature values as iOS does not provide this information.

You can call this function from any part of your code that needs to check the device's thermal state or battery temperature. The result will be a string that represents the thermal state on iOS or the battery temperature in Celsius on Android.

response_b:
Here is a C# function that retrieves the device's thermal state and battery temperature. Please note that the official Unity API does not provide direct access to this information. Therefore, we need to use native plugins for Android and iOS, which can interact with the operating system in a way that Unity's API cannot.

```csharp
using UnityEngine;
using UnityEngine.Android;

public class DeviceStats : MonoBehaviour
{
    public static float BatteryTemperature { get; private set; }
    public static int ThermalState { get; private set; }

    #if UNITY_ANDROID
        // Android Native Plugin
        [System.Serializable]
        class AndroidPlugin
        {
            static AndroidJavaClass unityPlayer = new AndroidJavaClass("com.unity3d.Player");
            static AndroidJavaObject currentActivity = unityPlayer.GetStatic<AndroidJavaObject>("currentActivity");
            static AndroidJavaClass activityClass = new AndroidJavaClass("android.app.Activity");
        }

        [System.Serializable]
        class BatteryTemperaturePlugin
        {
            static AndroidJavaObject batteryManager = AndroidPlugin.currentActivity.Call<AndroidJavaObject>("getSystemService", AndroidPlugin.activityClass.GetStatic<AndroidJavaObject>("BATTERY_SERVICE"));
            static AndroidJavaObject batteryStatus = batteryManager.Call<AndroidJavaObject>("getIntProperty", "TEMP");
            public static float GetBatteryTemperature()
            {
                return batteryStatus.Get<int>();
            }
        }

        [System.Serializable]
        class ThermalPlugin
        {
            static AndroidJavaObject thermalManager = AndroidPlugin.currentActivity.Call<AndroidJavaObject>("getSystemService", AndroidPlugin.activityClass.GetStatic<AndroidJavaObject>("THERMAL_SERVICE"));
            public static int GetThermalState()
            {
                return thermalManager.Call<int>("getThermalState");
            }
        }

        void Start()
        {
            BatteryTemperature = BatteryTemperaturePlugin.GetBatteryTemperature();
            ThermalState = ThermalPlugin.GetThermalState();
        }
    #elif UNITY_IOS
        // iOS Native Plugin
        [DllImport("__Internal")]
        private static extern float GetBatteryTemperature();

        [DllImport("__Internal")]
        private static extern int GetThermalState();

        void Start()
        {
            BatteryTemperature = GetBatteryTemperature();
            ThermalState = GetThermalState();
        }
    #endif
}
```
The Android part of this script uses the Android Java Native Interface (JNI) to interact with the Android operating system directly. On iOS, you'd need to use a C++ library and link it into your Unity project, then call those functions from your C# code.

Please note that this is just a sample code and might need adjustments based on the specific requirements of your project, and the accuracy of the battery temperature and thermal state might vary based on the device and the version of the operating system.
